#include <stdio.h>
#include <string.h>

int main() {
    int T; 
    if (scanf("%d", &T) != 1) return 0;
    char s[100005];
    while (T--) {
        scanf("%s", s);
        int groups = 0;
        int inGroup = 0;
        for (int i = 0; s[i]; ++i) {
            if (s[i] == '1') {
                if (!inGroup) {
                    groups++;
                    inGroup = 1;
                }
            } else {
                inGroup = 0;
            }
        }
        printf("%d\n", groups);
    }
    return 0;
}

