import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    t = int(data[0])
    idx = 1
    out_lines = []
    for _ in range(t):
        s = data[idx]; idx += 1
        groups = 0
        in_group = False
        for ch in s:
            if ch == '1':
                if not in_group:
                    groups += 1
                    in_group = True
            else:
                in_group = False
        out_lines.append(str(groups))
    sys.stdout.write('\n'.join(out_lines))

